import React from 'react';

const CompliancePage = () => {
  return (
    <div className="p-6 font-body">
      <h1 className="text-2xl font-display font-bold text-white mb-2">Compliance Center</h1>
      <p className="text-slate-400">View audit logs, compliance policies, and run scans.</p>

      <div className="mt-8 bg-surface-800 border border-surface-600 rounded-xl p-6 flex flex-col items-center justify-center text-center h-64">
        <div className="text-4xl mb-4">🛡️</div>
        <h3 className="text-white font-medium mb-2">Compliance Module</h3>
        <p className="text-slate-500 text-sm max-w-sm">This module is part of the enterprise compliance suite. Content will populate here based on client monitoring and AI conversation audits.</p>
      </div>
    </div>
  );
};

export default CompliancePage;
